'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'
import { Send, Clock } from 'lucide-react'
import Image from 'next/image'

interface Message {
  id: string
  role: 'user' | 'assistant'
  content: string
  created_at: string
}

const SUGGESTED_QUESTIONS = [
  'Örnek soru buraya',
  'Örnek soru buraya',
  'Örnek soru buraya',
  'Örnek soru buraya',
  'Örnek soru buraya',
  'Örnek soru buraya',
]

export default function ChatPage() {
  const { user, loading: authLoading, signOut } = useAuth()
  const router = useRouter()
  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!authLoading && !user) {
      router.push('/auth')
    }
  }, [user, authLoading, router])

  useEffect(() => {
    if (user) {
      loadMessages()
    }
  }, [user])

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const loadMessages = async () => {
    const { data } = await supabase
      .from('messages')
      .select('*')
      .eq('user_id', user?.id)
      .order('created_at', { ascending: true })
    
    if (data) {
      setMessages(data)
    }
  }

  const handleSend = async (question?: string) => {
    const messageText = question || input
    if (!messageText.trim() || !user) return

    setLoading(true)
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: messageText,
      created_at: new Date().toISOString(),
    }

    setMessages((prev) => [...prev, userMessage])
    setInput('')

    // Save user message to Supabase
    await supabase.from('messages').insert({
      user_id: user.id,
      role: 'user',
      content: messageText,
    })

    // Simulate AI response
    setTimeout(async () => {
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: 'İlhamın veya ihtiyacın ne zaman geleceği belli olmaz. Bu yüzden [Marka Adı] her an yanınızda. Mekân ve zaman kısıtlaması olmaksızın, haftanın her günü ve günün her saati AI desteğine erişebilirsiniz. Kesintisiz kullanım hakkıyla, kontrol her zaman sizin elinizde.',
        created_at: new Date().toISOString(),
      }

      setMessages((prev) => [...prev, assistantMessage])

      // Save assistant message to Supabase
      await supabase.from('messages').insert({
        user_id: user.id,
        role: 'assistant',
        content: assistantMessage.content,
      })

      setLoading(false)
    }, 1000)
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  if (authLoading || !user) {
    return null
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      {/* Header Logo */}
      <div className="flex justify-center pt-6 pb-2">
        <Image src="/baykus.png" alt="Baykuş" width={80} height={61} priority />
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 overflow-y-auto px-4 py-6">
        {messages.length === 0 ? (
          // Empty state with suggested questions
          <div className="flex flex-col items-center justify-center h-full min-h-[400px]">
            {/* Background watermark */}
            <div className="absolute opacity-10 pointer-events-none">
              <Image src="/baykus.png" alt="" width={300} height={230} className="opacity-50" />
            </div>

            {/* Suggested Questions */}
            <div className="flex flex-wrap gap-3 justify-center max-w-2xl relative z-10">
              {SUGGESTED_QUESTIONS.map((question, index) => (
                <button
                  key={index}
                  onClick={() => handleSend(question)}
                  className="px-5 py-2 border-2 border-[#0c003d] rounded-full text-sm text-[#0c003d] hover:bg-[#0c003d] hover:text-white transition-colors bg-white"
                >
                  {question}
                </button>
              ))}
            </div>
          </div>
        ) : (
          // Messages
          <div className="space-y-6 max-w-3xl mx-auto">
            {messages.map((message) => (
              <div key={message.id} className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                {message.role === 'assistant' && (
                  <div className="mr-3 flex-shrink-0">
                    <Image src="/baykus.png" alt="" width={40} height={30} />
                  </div>
                )}
                <div
                  className={`max-w-[80%] px-4 py-3 ${
                    message.role === 'user'
                      ? 'bg-[#0c003d] text-white rounded-2xl rounded-tr-sm'
                      : 'text-black'
                  }`}
                >
                  {message.role === 'assistant' && (
                    <p className="text-sm leading-relaxed">{message.content}</p>
                  )}
                  {message.role === 'user' && (
                    <p className="text-sm">{message.content}</p>
                  )}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="mr-3 flex-shrink-0">
                  <Image src="/baykus.png" alt="" width={40} height={30} />
                </div>
                <div className="text-[#0c003d]">Yazıyor...</div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="px-4 pb-6 pt-2">
        <div className="max-w-3xl mx-auto">
          <div className="flex items-center border-2 border-[#0c003d] rounded-full px-4 py-3 bg-white">
            <Clock size={20} className="text-[#0c003d] mr-3 flex-shrink-0" />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Bana soru sor"
              className="flex-1 bg-transparent outline-none text-[#0c003d] placeholder-[#9ca3af]"
              disabled={loading}
            />
            <button
              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="ml-3 text-[#0c003d] disabled:opacity-50 flex-shrink-0"
            >
              <Send size={20} />
            </button>
          </div>
          <p className="text-center text-xs text-gray-500 mt-2">
            Demo amaçlı yapılmıştır. Veriler profesyonel koç verisi değildir!
          </p>
        </div>
      </div>
    </div>
  )
}
